from flask import Flask, request
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST
from werkzeug.middleware.dispatcher import DispatcherMiddleware
from werkzeug.exceptions import NotFound
import re

app = Flask(__name__)

# Define a Counter metric with labels for user_id, session_id, and full request path
http_requests_total = Counter(
    'http_requests_total', 
    'Total HTTP Requests', 
    ['user_id', 'session_id', 'full_request_path']
)

# Sanitize input to prevent injection attacks
def sanitize_input(input_string):
    return re.sub(r'[^a-zA-Z0-9_\-/]', '', input_string)

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def track_request(path):
    user_id = sanitize_input(request.args.get('user_id', 'unknown'))
    session_id = sanitize_input(request.args.get('session_id', 'unknown'))
    full_request_path = sanitize_input(request.full_path)

    # Increment the counter for the specific user-path combination
    http_requests_total.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).inc()

    return "Request tracked", 200

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

# Middleware to handle 404 errors for non-existent paths
app.wsgi_app = DispatcherMiddleware(NotFound(), {'/app': app.wsgi_app})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)